function buildSuffixArray(s) {
    const suffixes = Array.from({ length: s.length }, (_, i) => [s.slice(i), i]);
    suffixes.sort((a, b) => a[0].localeCompare(b[0]));
    return suffixes.map(suffix => suffix[1]);
}

function longestCommonSubstring(s1, s2) {
    const s = s1 + '#' + s2;
    const sa = buildSuffixArray(s);
    const n1 = s1.length, n2 = s2.length;
    let maxLen = 0, result = '';
    for (let i = 1; i < s.length; i++) {
        if ((sa[i-1] < n1 && sa[i] > n1) || (sa[i-1] > n1 && sa[i] < n1)) {
            let j = sa[i-1], k = sa[i], l = 0;
            while (j + l < s.length && k + l < s.length && s[j + l] === s[k + l]) {
                l++;
            }
            if (l > maxLen) {
                maxLen = l;
                result = s.slice(j, j + l);
            }
        }
    }
    return result;
}

