#include <stdio.h>
#include <stdlib.h>
#include <string.h>

typedef struct Suffix {
    const char* str;
    int index;
} Suffix;

int cmp(const void* a, const void* b) {
    Suffix* sa = (Suffix*)a;
    Suffix* sb = (Suffix*)b;
    return strcmp(sa->str + sa->index, sb->str + sb->index);
}

int* buildSuffixArray(const char* s, int n) {
    Suffix* suffixes = (Suffix*)malloc(n * sizeof(Suffix));
    for (int i = 0; i < n; i++) {
        suffixes[i].str = s;
        suffixes[i].index = i;
    }
    qsort(suffixes, n, sizeof(Suffix), cmp);
    int* sa = (int*)malloc(n * sizeof(int));
    for (int i = 0; i < n; i++) sa[i] = suffixes[i].index;
    free(suffixes);
    return sa;
}

char* longestCommonSubstring(const char* s1, const char* s2) {
    int n1 = strlen(s1), n2 = strlen(s2);
    char* s = (char*)malloc(n1 + n2 + 2);
    strcpy(s, s1);
    s[n1] = '#';
    strcpy(s + n1 + 1, s2);
    s[n1 + n2 + 1] = '\0';
    int* sa = buildSuffixArray(s, n1 + n2 + 1);
    int maxLen = 0, start = 0;
    for (int i = 1; i < n1 + n2 + 1; i++) {
        if ((sa[i-1] < n1 && sa[i] > n1) || (sa[i-1] > n1 && sa[i] < n1)) {
            int j = sa[i-1], k = sa[i], l = 0;
            while (j + l < n1 + n2 + 1 && k + l < n1 + n2 + 1 && s[j + l] == s[k + l]) {
                l++;
            }
            if (l > maxLen) {
                maxLen = l;
                start = j;
            }
        }
    }
    char* result = (char*)malloc(maxLen + 1);
    strncpy(result, s + start, maxLen);
    result[maxLen] = '\0';
    free(s);
    free(sa);
    return result;
}

int main() {
    const char* s1 = "hello";
    const char* s2 = "world";
    char* result = longestCommonSubstring(s1, s2);
    printf("Longest Common Substring: %s\n", result);
    free(result);
    return 0;
}
// Output: Longest Common Substring: l

