std::vector<int> buildSuffixArray(const std::string& s) {
    int n = s.size();
    std::vector<std::pair<std::string, int>> suffixes(n);
    for (int i = 0; i < n; i++) {
        suffixes[i] = {s.substr(i), i};
    }
    std::sort(suffixes.begin(), suffixes.end());
    std::vector<int> sa(n);
    for (int i = 0; i < n; i++) sa[i] = suffixes[i].second;
    return sa;
}

